import React, { useState } from "react";
import axios from "axios";

const API_BASE = process.env.REACT_APP_API_BASE || "http://localhost:8000";

function App() {
  const [commitMessage, setCommitMessage] = useState("");
  const [files, setFiles] = useState("");
  const [complianceResult, setComplianceResult] = useState(null);
  const [riskResult, setRiskResult] = useState(null);

  const handleCheck = async () => {
    const filesArr = files.split(",").map(f => f.trim()).filter(f => f);
    const compliance = await axios.post(`${API_BASE}/api/compliance-check`, {
      commit_message: commitMessage,
      files: filesArr
    });
    setComplianceResult(compliance.data);

    const risk = await axios.post(`${API_BASE}/api/risk-score`, {
      commit_message: commitMessage,
      files: filesArr,
      lines_changed: 50,
      prev_bugs: 2,
      test_coverage: 85
    });
    setRiskResult(risk.data);
  };

  return (
    <div style={{padding:20}}>
      <h1>Sentinel Dashboard</h1>
      <input
        type="text"
        placeholder="Commit message"
        value={commitMessage}
        onChange={e => setCommitMessage(e.target.value)}
        style={{width:"100%", marginBottom:10}}
      />
      <input
        type="text"
        placeholder="Changed files (comma separated)"
        value={files}
        onChange={e => setFiles(e.target.value)}
        style={{width:"100%", marginBottom:10}}
      />
      <button onClick={handleCheck}>Check</button>

      {complianceResult && (
        <div>
          <h3>Compliance</h3>
          <pre>{JSON.stringify(complianceResult,null,2)}</pre>
        </div>
      )}
      {riskResult && (
        <div>
          <h3>Risk Score</h3>
          <pre>{JSON.stringify(riskResult,null,2)}</pre>
        </div>
      )}
    </div>
  );
}

export default App;
